function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalize(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/&nbsp;/g, ' ')
    .replace(/[^a-z0-9.+#/-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function containsTerm(text, term) {
  const normalized = normalize(term);
  if (!normalized) return false;
  const normalizedText = normalize(text);
  if (/^[a-z0-9.+#/-]{1,3}$/.test(normalized)) {
    return normalizedText.split(' ').includes(normalized);
  }
  return normalizedText.includes(normalized);
}

function matches(text, terms) {
  return terms.filter(term => containsTerm(text, term));
}

function containsWholeTerm(text, term) {
  const normalized = normalize(term);
  if (!normalized) return false;
  const normalizedText = ' ' + normalize(text) + ' ';
  return normalizedText.includes(' ' + normalized + ' ');
}

function hardMatches(text, terms) {
  return terms.filter(term => containsWholeTerm(text, term));
}

function detectHardExclusion(title, text, hasTargetTitle) {
  const bodySignals = [];

  for (const [reason, terms] of Object.entries(taxonomy.hardExclusions)) {
    const titleTerms = hardMatches(title, terms);
    if (titleTerms.length) {
      return {
        outOfScope: true,
        exclusionReason: reason,
        exclusionSignals: uniq(titleTerms.map(term => reason + ':title:' + term))
      };
    }

    const bodyTerms = hardMatches(text, terms);
    if (reason === 'non_permanent_engagement' && bodyTerms.length) {
      return {
        outOfScope: true,
        exclusionReason: reason,
        exclusionSignals: uniq(bodyTerms.map(term => reason + ':text:' + term))
      };
    }
    bodySignals.push(...bodyTerms.map(term => reason + ':text:' + term));
  }

  if (!hasTargetTitle && bodySignals.length) {
    const firstSignal = bodySignals[0];
    return {
      outOfScope: true,
      exclusionReason: firstSignal.split(':')[0],
      exclusionSignals: uniq(bodySignals)
    };
  }

  return {
    outOfScope: false,
    exclusionReason: '',
    exclusionSignals: []
  };
}

function clamp(value) {
  return Math.max(0, Math.min(100, Math.round(value)));
}

function uniq(values) {
  return [...new Set(values.filter(Boolean))];
}

function inferRemotePolicy(text) {
  const normalized = normalize(text);
  if (containsTerm(normalized, 'remote') || containsTerm(normalized, 'remoto')) return 'remote';
  if (containsTerm(normalized, 'hybrid') || containsTerm(normalized, 'ibrido')) return 'hybrid';
  if (containsTerm(normalized, 'onsite') || containsTerm(normalized, 'on site') || containsTerm(normalized, 'in sede')) return 'onsite';
  return 'unknown';
}

function inferSeniority(title, text) {
  const titleMatches = matches(title, taxonomy.seniorityTerms);
  if (titleMatches.some(term => ['cto', 'vp', 'director', 'head', 'direttore'].includes(term))) return 'executive/leadership';
  if (titleMatches.some(term => ['manager', 'responsabile', 'lead', 'principal'].includes(term))) return 'leadership/senior';
  if (matches(text, taxonomy.seniorityTerms).length) return 'senior/unclear';
  return 'unknown';
}

function inferCompanySize(text) {
  const startupSignals = matches(text, ['startup', 'scaleup', 'scale-up', 'early stage', 'seed', 'series a', 'founder', 'co-founder']);
  const enterpriseSignals = matches(text, ['enterprise', 'corporate', 'multinational', 'global', 'banking group', 'large company', 'regulated']);
  if (startupSignals.length && !enterpriseSignals.length) return { assumption: 'small/startup/scaleup', signals: startupSignals };
  if (enterpriseSignals.length && !startupSignals.length) return { assumption: 'large/enterprise', signals: enterpriseSignals };
  if (startupSignals.length && enterpriseSignals.length) return { assumption: 'mixed/unclear', signals: uniq([...startupSignals, ...enterpriseSignals]) };
  return { assumption: 'unknown', signals: [] };
}

function detectRoleFamily(title, text) {
  const ranked = taxonomy.roleFamilies.map(family => {
    const aliasMatches = uniq([
      ...matches(title, family.aliases).map(term => 'title:' + term),
      ...matches(text, family.aliases).map(term => 'text:' + term)
    ]);
    const positiveMatches = matches(text, family.positive);
    const negativeMatches = matches(text, family.negative);
    const score = aliasMatches.filter(term => term.startsWith('title:')).length * 35
      + aliasMatches.filter(term => term.startsWith('text:')).length * 16
      + Math.min(25, positiveMatches.length * 4)
      - Math.min(20, negativeMatches.length * 8);
    return { family, aliasMatches, positiveMatches, negativeMatches, score };
  }).sort((a, b) => b.score - a.score);

  const best = ranked[0];
  if (!best || best.score <= 0) {
    return {
      roleFamily: 'unknown',
      roleFamilyId: 'unknown',
      titleAliasConfidence: 0,
      roleFamilySignals: []
    };
  }

  return {
    roleFamily: best.family.label,
    roleFamilyId: best.family.id,
    titleAliasConfidence: clamp(Math.min(100, best.score)),
    roleFamilySignals: uniq([...best.aliasMatches, ...best.positiveMatches.slice(0, 8)]),
    roleFamilyNegativeSignals: best.negativeMatches
  };
}

function usefulDescriptionLength(record) {
  const metadataTerms = [
    record.title,
    record.company,
    record.location,
    record.url,
    'candidati con curriculum e profilo',
    'candidatura semplice',
    'questa azienda sta assumendo attivamente',
    'selezione attiva'
  ].filter(Boolean);
  let useful = normalize(record.description || record.body || '');
  for (const term of metadataTerms) {
    const normalizedTerm = normalize(term);
    if (normalizedTerm) useful = useful.replaceAll(normalizedTerm, ' ');
  }
  useful = useful.replace(/https?:\/\/[^\s]+/g, ' ').replace(/\s+/g, ' ').trim();
  return useful.length;
}

function isDataPoorAlertRecord(record, hasTargetTitle, hardGate) {
  return /alert email/i.test(record.source || '')
    && hasTargetTitle
    && !hardGate.outOfScope
    && usefulDescriptionLength(record) < 120;
}

function scoreRecord(record, options = {}) {
  const capturedAt = record.capturedAt || new Date().toISOString();
  const title = record.title || '';
  const description = record.description || record.body || '';
  const text = normalize([
    title,
    record.company,
    record.location,
    record.remotePolicy,
    description,
    asArray(record.tags).join(' ')
  ].join(' '));
  const titleText = normalize(title);
  const targetTitleMatches = matches(titleText, taxonomy.targetTitleTerms);
  const hasTargetTitle = targetTitleMatches.length > 0;
  const hardGate = detectHardExclusion(titleText, text, hasTargetTitle);
  const family = hardGate.outOfScope
    ? { roleFamily: 'out_of_scope', roleFamilyId: 'out_of_scope', titleAliasConfidence: 0, roleFamilySignals: [], roleFamilyNegativeSignals: [] }
    : detectRoleFamily(titleText, text);
  const seniority = inferSeniority(titleText, text);
  const companySize = inferCompanySize(text);
  const remotePolicy = record.remotePolicy || inferRemotePolicy(text);
  const excluded = matches(text, taxonomy.exclusions);
  const hardTitleExclusions = matches(titleText, taxonomy.hardTitleExclusions);
  const hasHardTitleExclusion = hardGate.outOfScope || (hardTitleExclusions.length > 0 && !hasTargetTitle);
  const domainMatches = matches(text, taxonomy.domains);
  const locationMatches = matches(text, taxonomy.locations);

  const responsibilitySignals = matches(text, [
    'ownership', 'owner', 'roadmap', 'architecture', 'architettura', 'delivery',
    'team', 'teams', 'platform', 'piattaforma', 'governance', 'budget',
    'stakeholder', 'vendor', 'modernization', 'modernizzazione'
  ]);
  const contextSignals = uniq([
    ...domainMatches,
    ...locationMatches,
    ...companySize.signals,
    remotePolicy !== 'unknown' ? remotePolicy : ''
  ]);

  const advantageMatches = {};
  for (const [key, terms] of Object.entries(taxonomy.candidateAdvantage)) {
    advantageMatches[key] = matches(text, terms);
  }

  const marketDemandScore = clamp(
    (options.observedAlertVolume || 0)
    + (options.externalJobCount || 0)
    + (options.trendVelocity || 0)
    + (options.macroTrendSupport || 0)
    + Math.min(10, family.titleAliasConfidence * 0.1)
  );

  let profileFitScore = clamp(
    family.titleAliasConfidence * 0.35
    + Math.min(25, responsibilitySignals.length * 6)
    + Math.min(20, domainMatches.length * 5)
    + Math.min(20, contextSignals.length * 4)
  );

  let candidateAdvantageScore = clamp(
    Math.min(25, advantageMatches.bankingOrRegulatedExperience.length * 7)
    + Math.min(25, advantageMatches.startupAndProductProof.length * 7)
    + Math.min(20, advantageMatches.platformAndCloudDepth.length * 5)
    + Math.min(15, advantageMatches.leadershipAndDeliveryProof.length * 4)
    + Math.min(15, advantageMatches.crossDomainTranslation.length * 4)
  );

  if (family.roleFamilyId === 'cto_fractional_founder' && companySize.assumption === 'small/startup/scaleup') {
    profileFitScore = clamp(profileFitScore + 12);
    candidateAdvantageScore = clamp(candidateAdvantageScore + 12);
  }
  if (family.roleFamilyId === 'cto_fractional_founder' && companySize.assumption === 'large/enterprise') {
    profileFitScore = clamp(profileFitScore - 12);
  }
  if (!hasTargetTitle && family.titleAliasConfidence < 50) {
    profileFitScore = clamp(profileFitScore - 30);
    candidateAdvantageScore = clamp(candidateAdvantageScore - 15);
  }
  if (excluded.length || hasHardTitleExclusion) {
    profileFitScore = hardGate.outOfScope ? 0 : clamp(profileFitScore - 70);
    candidateAdvantageScore = hardGate.outOfScope ? 0 : clamp(candidateAdvantageScore - 50);
  }

  const dataPoor = isDataPoorAlertRecord(record, hasTargetTitle, hardGate);
  let applicationPriorityScore = hardGate.outOfScope ? 0 : clamp(
    marketDemandScore * 0.25
    + profileFitScore * 0.45
    + candidateAdvantageScore * 0.30
  );
  if (dataPoor) {
    applicationPriorityScore = clamp(Math.max(applicationPriorityScore, 45));
  }

  let recommendedAction = 'ignore';
  if (applicationPriorityScore >= 80 && profileFitScore >= 70) recommendedAction = 'apply';
  else if (applicationPriorityScore >= 60) recommendedAction = 'inspect manually';
  else if (applicationPriorityScore >= 40) recommendedAction = 'monitor';
  if (excluded.length || hasHardTitleExclusion || (!hasTargetTitle && profileFitScore < 45)) recommendedAction = 'ignore';
  if (dataPoor && recommendedAction !== 'apply') recommendedAction = 'inspect manually';

  const marketDemandSignals = uniq([
    options.sourceKind || '',
    hasTargetTitle ? 'target title match' : '',
    family.titleAliasConfidence >= 50 ? 'title-alias confidence' : '',
    options.externalJobCount ? 'public feed occurrence' : '',
    options.observedAlertVolume ? 'observed alert volume' : ''
  ]);
  const profileFitSignals = uniq([
    ...family.roleFamilySignals.slice(0, 8),
    ...responsibilitySignals.slice(0, 8),
    ...domainMatches.slice(0, 8)
  ]);
  const candidateAdvantageSignals = uniq(Object.entries(advantageMatches)
    .filter(([, values]) => values.length)
    .map(([key, values]) => key + ': ' + values.slice(0, 4).join(', ')));

  const explanationParts = [
    'observed title "' + (title || 'n/a') + '" from ' + (record.source || 'unknown source'),
    'inferred role family ' + family.roleFamily,
    'scores demand/profile/advantage/priority = ' + marketDemandScore + '/' + profileFitScore + '/' + candidateAdvantageScore + '/' + applicationPriorityScore
  ];
  if (profileFitSignals.length) explanationParts.push('fit signals: ' + profileFitSignals.slice(0, 6).join(', '));
  if (hardGate.outOfScope) explanationParts.push('excluded before scoring: ' + hardGate.exclusionReason);
  if (candidateAdvantageSignals.length) explanationParts.push('advantage signals: ' + candidateAdvantageSignals.slice(0, 3).join('; '));
  if (targetTitleMatches.length) explanationParts.push('target title signals: ' + targetTitleMatches.slice(0, 4).join(', '));
  if (dataPoor) explanationParts.push('data-poor alert: title/company/location/link only; manual inspection required');
  if (excluded.length || hardTitleExclusions.length || hardGate.exclusionSignals.length) explanationParts.push('exclusion signals: ' + uniq([...excluded, ...hardTitleExclusions, ...hardGate.exclusionSignals]).join(', '));
  if (companySize.assumption !== 'unknown') explanationParts.push('company size assumption: ' + companySize.assumption);

  return {
    source: record.source || '',
    capturedAt,
    title,
    company: record.company || '',
    location: record.location || '',
    remotePolicy,
    url: record.url || '',
    description,
    dataPoor,
    enrichmentStatus: dataPoor ? 'not_attempted' : 'not_needed',
    enrichmentSource: '',
    roleFamily: family.roleFamily,
    roleFamilyId: family.roleFamilyId,
    outOfScope: hardGate.outOfScope,
    exclusionReason: hardGate.exclusionReason,
    exclusionSignals: hardGate.exclusionSignals,
    seniority,
    companySizeAssumption: companySize.assumption,
    companySizeSignals: companySize.signals,
    marketDemandScore,
    profileFitScore,
    candidateAdvantageScore,
    applicationPriorityScore,
    marketDemandSignals,
    profileFitSignals,
    candidateAdvantageSignals,
    recommendedAction,
    explanation: explanationParts.join('; '),
    tags: asArray(record.tags),
    publishedAt: record.publishedAt || '',
    emailId: record.emailId || '',
    subject: record.subject || '',
    from: record.from || ''
  };
}

const minPriorityScore = 35;
const limit = 10;

function stripHtml(value) {
  return String(value || '')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/(p|div|li|tr|h[1-6])>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/[\u034f\u200b-\u200f\u202a-\u202e\u2060-\u206f]/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function firstString(...values) {
  return values.find(value => typeof value === 'string' && value.trim()) || '';
}

function extractBody(email) {
  const direct = firstString(email.textPlain, email.text, email.textHtml, email.html, email.snippet);
  if (direct) return stripHtml(direct);
  const payload = email.payload || {};
  const parts = Array.isArray(payload.parts) ? payload.parts : [];
  const bodyParts = parts
    .map(part => part.body?.data || part.body?.attachmentId || '')
    .filter(Boolean)
    .join(' ');
  return stripHtml(firstString(bodyParts, email.snippet));
}

function extractUrls(text) {
  const urls = String(text || '').match(/https?:\/\/[^\s"'<>]+/g) || [];
  return [...new Set(urls.map(url => url.replace(/[),.;]+$/g, '')))].slice(0, 8);
}

