function shouldEnrichRecord(record) {
  return record
    && record.dataPoor === true
    && record.recommendedAction === 'inspect manually'
    && /^https:\/\/www\.linkedin\.com\/(comm\/)?jobs\/view\/\d+/i.test(record.url || '');
}

function extractJobDetailText(value) {
  const text = stripHtml(value)
    .replace(/\bLinkedIn\b/gi, ' ')
    .replace(/\bSign in\b|\bJoin now\b|\bApply now\b/gi, ' ')
    .replace(/\bSkip to main content\b/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return text.slice(0, 4000);
}

async function fetchJobDetail(record) {
  const headers = {
    Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
    'User-Agent': 'Mozilla/5.0 job-alert-enrichment'
  };

  try {
    let response;
    if (typeof $helpers !== 'undefined' && typeof $helpers.httpRequest === 'function') {
      response = await $helpers.httpRequest({
        method: 'GET',
        url: record.url,
        headers,
        timeout: 15000
      });
    } else if (typeof fetch === 'function') {
      let timeoutId;
      const controller = typeof AbortController === 'function' ? new AbortController() : null;
      if (controller) timeoutId = setTimeout(() => controller.abort(), 15000);
      const fetched = await fetch(record.url, {
        method: 'GET',
        headers,
        signal: controller ? controller.signal : undefined
      });
      if (timeoutId) clearTimeout(timeoutId);
      response = await fetched.text();
    } else {
      return { status: 'skipped', text: '', error: 'no http helper or fetch available' };
    }

    const raw = typeof response === 'string' ? response : JSON.stringify(response || '');
    const text = extractJobDetailText(raw);
    if (text.length < 120) return { status: 'empty', text: '', error: 'detail page returned too little text' };
    return { status: 'fetched', text, error: '' };
  } catch (error) {
    return { status: 'failed', text: '', error: String(error && error.message ? error.message : error).slice(0, 180) };
  }
}

async function enrichScoredRecords(records) {
  const candidates = records.filter(shouldEnrichRecord).slice(0, enrichmentLimit);
  if (!candidates.length) return records;

  const byEmailId = new Map();
  for (const record of candidates) {
    const detail = await fetchJobDetail(record);
    if (detail.status !== 'fetched') {
      byEmailId.set(record.emailId, {
        ...record,
        enrichmentStatus: detail.status,
        enrichmentSource: record.url,
        enrichmentError: detail.error,
        explanation: record.explanation + '; enrichment ' + detail.status + (detail.error ? ': ' + detail.error : '')
      });
      continue;
    }

    const rescored = scoreRecord({
      ...record,
      description: [record.description, 'Fetched job detail:', detail.text].filter(Boolean).join('\n\n')
    }, scoreOptions);
    rescored.enrichmentStatus = 'fetched';
    rescored.enrichmentSource = record.url;
    rescored.enrichmentError = '';
    if (record.recommendedAction === 'inspect manually'
      && rescored.recommendedAction !== 'apply'
      && !rescored.outOfScope
      && rescored.applicationPriorityScore >= minPriorityScore) {
      rescored.recommendedAction = 'inspect manually';
    }
    rescored.explanation = rescored.explanation + '; enriched from job detail page';
    byEmailId.set(record.emailId, rescored);
  }

  return records.map(record => byEmailId.get(record.emailId) || record);
}

function inferSource(email, body) {
  const text = normalize([email.from?.value?.[0]?.address, email.from, email.subject, body].join(' '));
  if (text.includes('linkedin')) return 'LinkedIn alert email';
  if (text.includes('indeed')) return 'Indeed alert email';
  if (text.includes('otta')) return 'Otta alert email';
  if (text.includes('wellfound') || text.includes('angellist')) return 'Wellfound alert email';
  return 'Job alert email';
}

function inferTitle(email, body) {
  const subject = String(email.subject || '').replace(/^(LinkedIn|Indeed|Job Alert|Offerte di lavoro)[: -]+/i, '').trim();
  const chunks = body.split(/[.|\n\r]+/).map(line => line.trim()).filter(Boolean);
  const allAliases = taxonomy.roleFamilies.flatMap(family => family.aliases);
  const roleLine = chunks.find(line => matches(line, allAliases).length > 0);
  return firstString(roleLine, subject, email.snippet, 'Job alert match').slice(0, 180);
}

function cleanupAlertText(value) {
  return String(value || '')
    .replace(/[\u034f\u200b-\u200f\u202a-\u202e\u2060-\u206f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanupAlertLines(value) {
  return String(value || '')
    .replace(/[\u034f\u200b-\u200f\u202a-\u202e\u2060-\u206f]/g, '')
    .replace(/\r\n/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function canonicalJobUrl(url) {
  const match = String(url || '').match(/https?:\/\/www\.linkedin\.com\/comm\/jobs\/view\/(\d+)/i)
    || String(url || '').match(/https?:\/\/www\.linkedin\.com\/jobs\/view\/(\d+)/i);
  return match ? 'https://www.linkedin.com/comm/jobs/view/' + match[1] : String(url || '').trim();
}

function linkedinLineSection(body) {
  let section = cleanupAlertLines(body);
  const startMarkers = [
    'Riceverai notifiche quando vengono pubblicate nuove offerte di lavoro che corrispondono alle tue preferenze di ricerca.',
    'Il tuo avviso di offerte di lavoro è stato creato:',
    'Il tuo avviso di offerte di lavoro e stato creato:'
  ];
  for (const marker of startMarkers) {
    const index = section.indexOf(marker);
    if (index >= 0) {
      section = section.slice(index + marker.length).trim();
      break;
    }
  }

  const endMarkers = [
    'Vedi tutte le offerte di lavoro',
    'Il destinatario di questa email',
    'Stai ricevendo avvisi',
    'Gestisci gli avvisi'
  ];
  const endIndexes = endMarkers
    .map(marker => section.indexOf(marker))
    .filter(index => index >= 0);
  if (endIndexes.length) section = section.slice(0, Math.min(...endIndexes)).trim();
  return section;
}

function linkedinJobSection(body) {
  return cleanupAlertText(linkedinLineSection(body));
}

function titleStartPattern() {
  return [
    'Chief Technology Officer',
    'CTO',
    'Head of Engineering',
    'Engineering Manager',
    'Engineering Lead(?:[- ][A-Za-z0-9 /&]+)?',
    'Technical Director(?:[- ][A-Za-z0-9 /&()]+)?',
    'Technical Lead(?:\\/ Head of Tech)?',
    'Head of Tech',
    'AI[- ]Native Software Engineering Director',
    'Software Engineering Director',
    'Platform Engineering Lead',
    'Cloud Engineering Manager',
    'DevOps Lead',
    'AI Solutions? Architect',
    'Applied AI Lead',
    'AI Lead',
    'Data Platform Lead',
    'Director of Engineering',
    'VP Engineering',
    'R:\\s*TMS System engineering'
  ].join('|');
}

function isLinkedInMetadataLine(line) {
  return /^(\d+ collegament[oi]|Candidati con curriculum e profilo|Candidatura semplice|Questa azienda sta assumendo attivamente|Selezione attiva)$/i.test(line);
}

function isLinkedInIntroLine(line) {
  return /^Il tuo avviso di offerte di lavoro/i.test(line)
    || /^Riceverai notifiche/i.test(line)
    || /^Vedi le nuove offerte/i.test(line);
}

function splitLinkedInLineJobs(email, body) {
  const section = linkedinLineSection(body);
  if (!section) return [];

  const chunks = section
    .split(/\n\s*-{20,}\s*\n/g)
    .map(chunk => chunk.split(/\n/).map(line => line.trim()).filter(Boolean))
    .filter(lines => lines.length);

  const jobs = [];
  for (const lines of chunks) {
    const urlIndex = lines.findIndex(line => /^Visualizza offerta di lavoro:/i.test(line));
    if (urlIndex < 0) continue;

    const rawUrl = lines[urlIndex].replace(/^Visualizza offerta di lavoro:\s*/i, '').trim();
    const url = canonicalJobUrl(rawUrl);
    const beforeUrl = lines
      .slice(0, urlIndex)
      .filter(line => !isLinkedInIntroLine(line));

    const titleIndex = beforeUrl.findIndex((line, index) => {
      return index + 2 < beforeUrl.length
        && !line.includes('http')
        && !isLinkedInMetadataLine(line);
    });
    if (titleIndex < 0) continue;

    const title = beforeUrl[titleIndex];
    const company = beforeUrl[titleIndex + 1] || '';
    const location = beforeUrl[titleIndex + 2] || '';
    const metadata = beforeUrl.slice(titleIndex + 3).filter(isLinkedInMetadataLine);
    const chunkText = lines.join('\n');

    jobs.push({
      source: 'LinkedIn alert email',
      capturedAt: new Date().toISOString(),
      emailId: (email.id || email.messageId || '') + '#' + (jobs.length + 1),
      subject: email.subject || '',
      from: email.from?.value?.[0]?.address || email.from || '',
      title: title.slice(0, 180),
      company,
      location,
      remotePolicy: inferRemotePolicy([location, chunkText].join(' ')),
      url,
      description: metadata.length ? metadata.join('; ') : chunkText,
      publishedAt: email.date || email.internalDate || ''
    });
  }

  return jobs;
}

function splitLinkedInDotJobs(email, body) {
  const section = linkedinJobSection(body);
  if (!section || !section.includes('·')) return [];

  const pattern = new RegExp('(?:^|\\s)(' + titleStartPattern() + ')\\b', 'gi');
  const starts = [];
  let match;
  while ((match = pattern.exec(section)) !== null) {
    starts.push(match.index + (match[0].startsWith(' ') ? 1 : 0));
  }

  const uniqueStarts = [...new Set(starts)].sort((a, b) => a - b);
  const chunks = uniqueStarts.map((start, index) => {
    const end = uniqueStarts[index + 1] ?? section.length;
    return section.slice(start, end).trim();
  }).filter(chunk => chunk.includes('·'));

  return chunks.map((chunk, index) => {
    const beforeDot = chunk.split('·')[0].trim();
    const afterDot = chunk.slice(chunk.indexOf('·') + 1).trim();
    const location = afterDot
      .replace(/\b(\d+ collegament[oi]|Candidatura semplice|Selezione attiva)\b.*$/i, '')
      .trim();

    return {
      source: 'LinkedIn alert email',
      capturedAt: new Date().toISOString(),
      emailId: (email.id || email.messageId || '') + '#' + (index + 1),
      subject: email.subject || '',
      from: email.from?.value?.[0]?.address || email.from || '',
      title: beforeDot.slice(0, 180),
      company: '',
      location,
      remotePolicy: inferRemotePolicy([location, chunk].join(' ')),
      url: '',
      description: chunk,
      publishedAt: email.date || email.internalDate || ''
    };
  });
}

function splitLinkedInJobs(email, body) {
  const source = inferSource(email, body);
  if (source !== 'LinkedIn alert email') return [];

  const lineJobs = splitLinkedInLineJobs(email, body);
  if (lineJobs.length) return lineJobs;

  return splitLinkedInDotJobs(email, body);
}

function fallbackEmailRecord(email, body) {
  const urls = extractUrls([body, email.textHtml, email.snippet].join(' '));
  const title = inferTitle(email, body);
  return {
    source: inferSource(email, body),
    capturedAt: new Date().toISOString(),
    emailId: email.id || email.messageId || '',
    subject: email.subject || '',
    from: email.from?.value?.[0]?.address || email.from || '',
    title,
    company: '',
    location: '',
    remotePolicy: inferRemotePolicy(body),
    url: urls.find(url => /linkedin|indeed|otta|wellfound|angellist|jobs|career/i.test(url)) || urls[0] || '',
    description: body,
    publishedAt: email.date || email.internalDate || ''
  };
}

const parsed = $input.all().flatMap(item => {
  const email = item.json;
  const body = extractBody(email);
  const linkedInJobs = splitLinkedInJobs(email, body);
  return linkedInJobs.length ? linkedInJobs : [fallbackEmailRecord(email, body)];
});

const initiallyScoredRecords = parsed.map(record => scoreRecord(record, scoreOptions));
const scoredRecords = await enrichScoredRecords(initiallyScoredRecords);

const topMatches = scoredRecords
  .filter(job => job.applicationPriorityScore >= minPriorityScore && job.recommendedAction !== 'ignore')
  .sort((a, b) => b.applicationPriorityScore - a.applicationPriorityScore || b.profileFitScore - a.profileFitScore)
  .slice(0, limit);

const generatedAt = new Date().toISOString();
const familySummary = scoredRecords.reduce((acc, job) => {
  const key = job.roleFamily || 'unknown';
  if (!acc[key]) acc[key] = { count: 0, maxPriority: 0 };
  acc[key].count += 1;
  acc[key].maxPriority = Math.max(acc[key].maxPriority, job.applicationPriorityScore);
  return acc;
}, {});

const markdown = [
  '# Job Alert Email Matches',
  '',
  `Generated: ${generatedAt}`,
  `Emails parsed: ${parsed.length}`,
  `Matches: ${topMatches.length}`,
  '',
  ...topMatches.flatMap((job, index) => [
    `## ${index + 1}. ${job.title}`,
    '',
    `- Action: ${job.recommendedAction}`,
    `- Priority: ${job.applicationPriorityScore}`,
    `- Demand/Profile/Advantage: ${job.marketDemandScore}/${job.profileFitScore}/${job.candidateAdvantageScore}`,
    `- Role family: ${job.roleFamily}`,
    `- Seniority: ${job.seniority}`,
    `- Company size assumption: ${job.companySizeAssumption}`,
    `- Source: ${job.source}`,
    `- Subject: ${job.subject}`,
    `- URL: ${job.url || 'n/a'}`,
    `- Explanation: ${job.explanation}`,
    ''
  ])
].join('\n');

return [{
  json: {
    generatedAt,
    parsedCount: parsed.length,
    matchCount: topMatches.length,
    minPriorityScore,
    familySummary,
    records: scoredRecords,
    matches: topMatches,
    markdown
  }
}];

function decodeHtmlEntities(value) {
  return String(value ?? '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#x27;/gi, "'");
}

function text(value) {
  const withoutTags = String(value ?? '')
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/(p|div|li|h[1-6])>/gi, '\n')
    .replace(/<[^>]*>/g, '');

  return decodeHtmlEntities(withoutTags)
    .replace(/[<>]/g, '')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function oneLine(value) {
  return text(value).replace(/\s+/g, ' ').trim();
}

function shorten(value, maxLength) {
  const clean = oneLine(value);
  if (clean.length <= maxLength) return clean;
  return clean.slice(0, maxLength - 1).trimEnd() + '...';
}

function uniqueByUrlOrTitle(jobs) {
  const seen = new Set();
  const result = [];
  for (const job of jobs) {
    const key = String(job.url || '').trim() || oneLine(job.title || '').toLowerCase();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    result.push(job);
  }
  return result;
}

function sortJobs(jobs) {
  return [...jobs].sort((a, b) =>
    (b.applicationPriorityScore || 0) - (a.applicationPriorityScore || 0)
    || (b.profileFitScore || 0) - (a.profileFitScore || 0)
  );
}

function jobLines(jobs) {
  if (!jobs.length) return 'Nessun elemento.';
  return jobs.map((job, index) => {
    const title = shorten(job.title || 'n/a', 90);
    const company = shorten(job.company || '', 55);
    const source = shorten(job.source || 'email alert', 60);
    const priority = oneLine(job.applicationPriorityScore ?? 'n/a');
    const action = oneLine(job.recommendedAction || 'n/a');
    const url = String(job.url || '').trim();
    const enrichmentStatus = oneLine(job.enrichmentStatus || '');
    const enrichmentLine = enrichmentStatus && !['not_attempted', 'not_needed'].includes(enrichmentStatus)
      ? 'Enrichment: ' + enrichmentStatus
      : '';
    const heading = company ? (index + 1) + '. ' + title + ' - ' + company : (index + 1) + '. ' + title;
    return [
      heading,
      source + ' | Priority: ' + priority + ' | Action: ' + action,
      enrichmentLine,
      url
    ].filter(Boolean).join('\n');
  }).join('\n\n');
}

const report = $input.first().json;
const generated = report.generatedAt ? new Date(report.generatedAt).toISOString().replace('T', ' ').slice(0, 16) + ' UTC' : 'n/a';
const records = Array.isArray(report.records) ? report.records : [];
const matches = Array.isArray(report.matches) ? report.matches : [];
const applyMatches = uniqueByUrlOrTitle(matches.filter(job => job.recommendedAction === 'apply')).slice(0, 5);
const manualInspection = uniqueByUrlOrTitle([
  ...matches.filter(job => job.recommendedAction === 'inspect manually'),
  ...sortJobs(records.filter(job => !job.outOfScope && job.recommendedAction === 'inspect manually'))
]).slice(0, 5);
const belowThreshold = sortJobs(records.filter(job =>
  !job.outOfScope
  && !['apply', 'inspect manually'].includes(job.recommendedAction)
)).slice(0, (applyMatches.length || manualInspection.length) ? 3 : 5);

const message = [
  'Job Search Email Alerts',
  generated,
  '',
  'Emails parsed: ' + report.parsedCount,
  'Apply matches: ' + applyMatches.length,
  'Manual inspection: ' + manualInspection.length,
  '',
  'Matches',
  jobLines(applyMatches),
  '',
  'Needs manual inspection',
  jobLines(manualInspection),
  '',
  'Below threshold',
  jobLines(belowThreshold)
].join('\n');

return [{
  json: {
    ...report,
    telegramMessage: message.slice(0, 3900)
  }
}];
